21→export const Chip = React.memo(function Chip({
22→  label,
23→  selected,
24→  onPress,
25→  accessibilityLabel,
26→}: ChipProps) {
27→  const progress = useSharedValue(selected ? 1 : 0);
28→  progress.value = withSpring(selected ? 1 : 0, motion.snappy);
29→
30→  const animatedStyle = useAnimatedStyle(() => ({
31→    backgroundColor: interpolateColor(
