 1→import React from 'react';
 2→import Animated, {
 3→  interpolate,
 4→  interpolateColor,
 5→  useAnimatedStyle,
 6→  useSharedValue,
 7→  withSpring,
 8→} from 'react-native-reanimated';
 9→import MaterialCommunityIcons from 'react-native-vector-icons/MaterialCommunityIcons';
10→
11→import { colors } from '../../theme/colors';
12→import { motion } from '../../theme/motion';
13→import { tabBarIcons } from './tabBarIcons';
14→
15→const AnimatedIcon = Animated.createAnimatedComponent(MaterialCommunityIcons);
16→
17→interface TabBarIconProps {
18→  routeName: keyof typeof tabBarIcons;
19→  focused: boolean;
20→}
21→
22→export function TabBarIcon({ routeName, focused }: TabBarIconProps) {
23→  const progress = useSharedValue(focused ? 1 : 0);
24→  progress.value = withSpring(focused ? 1 : 0, motion.snappy);
25→
26→  const animatedStyle = useAnimatedStyle(() => {
27→    const scale = interpolate(progress.value, [0, 1], [1.0, 1.15]);
28→    const color = interpolateColor(
29→      progress.value,
30→      [0, 1],
31→      [colors.mutedInk, colors.brand]
32→    );
33→    return {
34→      transform: [{ scale }],
35→      color,
36→    };
37→  });
38→
39→  const iconName = focused
40→    ? tabBarIcons[routeName].active
41→    : tabBarIcons[routeName].inactive;
42→
43→  return (
44→    <AnimatedIcon
45→      name={iconName}
46→      size={24}
47→      style={animatedStyle}
48→    />
49→  );
50→}
