 1→import React from 'react';
 2→import { StyleSheet } from 'react-native';
 3→import Animated, {
 4→  useAnimatedStyle,
 5→  withSpring,
 6→} from 'react-native-reanimated';
 7→
 8→import { colors } from '../../theme/colors';
 9→
10→interface TabBarIndicatorPillProps {
11→  tabCount: number;
12→  activeIndex: number;
13→  tabWidth: number;
14→}
15→
16→export function TabBarIndicatorPill({ tabCount, activeIndex, tabWidth }: TabBarIndicatorPillProps) {
17→  const animatedStyle = useAnimatedStyle(() => {
18→    const centerOffset = (tabWidth - 64) / 2;
19→    return {
20→      transform: [
21→        {
22→          translateX: withSpring(activeIndex * tabWidth + centerOffset, {
23→            damping: 20,
24→            stiffness: 200,
25→            mass: 0.8,
26→          }),
27→        },
28→      ],
29→    };
30→  });
31→
32→  return <Animated.View style={[styles.pill, animatedStyle]} />;
33→}
34→
